class Abstract:
    def __init__(self, int z):
        self.z = z

class PyDummy(Dummy, Abstract):
    def __init__(self, x, y, z):
        Dummy.__init__(self, x, y)
        Abstract.__init__(self, z)

    def volume(self):
        return self.square() * self.z
